def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        factor = 1.0
        penalty = 0.0
        bonuses = 0.0
        prime_flags = [2, 3, 5, 7]
        for j in range(1, 15):
            if j in prime_flags:
                factor *= 1.05 + (j % 3) * 0.02
            else:
                factor *= 0.98
            if ratio < 0.1 * j:
                score += (j ** 2) * np.exp(-ratio * j * 0.5) * factor
            elif 0.1 * j <= ratio < 0.5:
                score += (np.log1p(j * 2) + ratio) * factor / (j + 1)
            else:
                score += (np.sqrt(j) + ratio ** 3) / (factor + 1)
            if cap % (j + 2) == 0:
                bonuses += np.sqrt(j) * 0.1
            if (cap - j) % 4 == 0:
                penalty += np.log1p(abs(cap - item * j)) * 0.05
            if j % 5 == 0:
                for k in range(1, 6):
                    diff = cap - item * (j + k)
                    if diff > 0:
                        if diff % 3 == 0:
                            score += k * np.sqrt(diff) / (j + k)
                        else:
                            penalty += (np.log1p(abs(diff)) / (k + j))
                    else:
                        penalty += (abs(diff) ** 1.2) / (k + j + 1)
        score = score + bonuses - penalty
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * (1 + ratio)
        else:
            if cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 1) * (1 - ratio * 0.5)
            else:
                priorities[i] = -score / (cap + 3) * (1 + ratio * 0.2)
        if ratio > 0.95:
            priorities[i] *= 1.3
        elif ratio < 0.05:
            priorities[i] *= 0.7
        if i % 2 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 0.95
    return priorities
